proof_block:
// `Array::set` has two ensures clauses, one for each candidate run:
//   post.seq@ =~= old(self).seq@.update(i as int, out)
//   post.wf()
// They are connected by `=~=` (Seq extensional equality), which Verus
// needs help "lining up" across the two runs. The helper lemma
// `lemma_array_set_seq_unique` does that triangulation once, deriving
// `post1.seq@ == post2.seq@` (and hence `post1.seq == post2.seq` for
// the `Ghost<Seq<A>>` field) from the two ensures clauses applied to
// the same `(pre, i, out)`.
lemma_array_set_seq_unique::<A, N>(pre_self_, i, out, post1_self_, post2_self_);

// Re-pull the two ensures-conjuncts so triggers for Seq::update fire
// directly on `post1_self_.seq@` and `post2_self_.seq@`.
assert(post1_self_.seq@ =~= pre_self_.seq@.update(i as int, out));
assert(post2_self_.seq@ =~= pre_self_.seq@.update(i as int, out));

// Transitive Seq extensional equality through the shared RHS.
assert(post1_self_.seq@ =~= post2_self_.seq@);
assert(post1_self_.seq@ == post2_self_.seq@);

// `Ghost<Seq<A>>` is determined by its `@`, so seq-field equality follows.
assert(post1_self_.seq == post2_self_.seq);

// `r1` and `r2` are both unit values, so they are trivially equal.
assert(r1 == r2);

// Promote view equality to full Array structural equality. The Array
// struct only exposes `seq@` through `view()` / `spec_index`; with both
// seq fields proven equal, the Array spec content is fully determined.
assert(post1_self_@ == post2_self_@);
assert(post1_self_ =~= post2_self_);
assert(post1_self_ == post2_self_);

helper_lemmas:
proof fn lemma_array_set_seq_unique<A, const N: usize>(
    pre_: Array<A, N>,
    i: usize,
    out: A,
    post1_: Array<A, N>,
    post2_: Array<A, N>,
)
    requires
        0 <= i < N,
        pre_.wf(),
        post1_.seq@ =~= pre_.seq@.update(i as int, out),
        post1_.wf(),
        post2_.seq@ =~= pre_.seq@.update(i as int, out),
        post2_.wf(),
    ensures
        post1_.seq@ == post2_.seq@,
        post1_.seq == post2_.seq,
        post1_.seq@.len() == N,
        post2_.seq@.len() == N,
        post1_.seq@.len() == post2_.seq@.len(),
        forall|k: int| 0 <= k < N ==> #[trigger] post1_.seq@[k] == post2_.seq@[k],
{
    assert(post1_.seq@ =~= pre_.seq@.update(i as int, out));
    assert(post2_.seq@ =~= pre_.seq@.update(i as int, out));
    assert(post1_.seq@ =~= post2_.seq@);
    assert(post1_.seq@ == post2_.seq@);
    assert(post1_.seq == post2_.seq);
    assert forall|k: int| 0 <= k < N implies #[trigger] post1_.seq@[k] == post2_.seq@[k] by {
        assert(post1_.seq@[k] == post2_.seq@[k]);
    }
}
